        // Tests validation error when string exceeds max_length
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/string_max_length_constraint_violation");
        request.Headers.Add("x-token", "test-token");
        var response = await client.SendAsync(request);
        Assert.Equal(422, (int)response.StatusCode);
        var bodyText = await response.Content.ReadAsStringAsync();
        var body = JsonDocument.Parse(bodyText).RootElement;
        var expectedBody = JsonDocument.Parse("{\"detail\":\"1 validation error in request\",\"errors\":[{\"ctx\":{\"max_length\":50},\"input\":\"this_is_a_very_long_query_string_that_exceeds_maximum_length_limit_for_this_parameter\",\"loc\":[\"query\",\"q\"],\"msg\":\"String should have at most 50 characters\",\"type\":\"string_too_long\"}],\"status\":422,\"title\":\"Request Validation Failed\",\"type\":\"https://spikard.dev/errors/validation-error\"}").RootElement;
        Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
    }

