    [Fact]    public async Task Test_StringRegexPatternMismatch()
    {
        // Tests validation error when string doesn't match regex pattern
        var baseUrl = Environment.GetEnvironmentVariable("MOCK_SERVER_URL") ?? "http://localhost:8080";
        using var handler = new System.Net.Http.HttpClientHandler { AllowAutoRedirect = false };
        using var client = new System.Net.Http.HttpClient(handler);
        var request = new System.Net.Http.HttpRequestMessage(System.Net.Http.HttpMethod.Get, $"{baseUrl}/fixtures/string_regex_pattern_mismatch");
        request.Headers.Add("x-token", "test-token");
        var response = await client.SendAsync(request);
        Assert.Equal(422, (int)response.StatusCode);
        var bodyText = await response.Content.ReadAsStringAsync();
        var body = JsonDocument.Parse(bodyText).RootElement;
        var expectedBody = JsonDocument.Parse("{\"detail\":\"1 validation error in request\",\"errors\":[{\"ctx\":{\"pattern\":\"^[a-zA-Z0-9_-]+$\"},\"input\":\"invalid!\",\"loc\":[\"query\",\"q\"],\"msg\":\"String should match pattern '^[a-zA-Z0-9_-]+$'\",\"type\":\"string_pattern_mismatch\"}],\"status\":422,\"title\":\"Request Validation Failed\",\"type\":\"https://spikard.dev/errors/validation-error\"}").RootElement;
        Assert.Equal(expectedBody.GetRawText(), body.GetRawText());
    }


